def entropy_score(text: str) -> float:
    unique = len(set(text))
    total = len(text)
    if total == 0:
        return 1.0
    return round(1 - (unique / total), 3)
def drift_flags(text: str) -> list:
    flags = []
    if re.search(r"\b(\w+)\s+\1\s+\1\b", text):
        flags.append("repetition")
    if len(text) > 300 and text.count('.') < 2:
        flags.append("runon")
    return flags
